/**
 * @summary Update app configuration
 */
export const getUpdateConfigUrl = () => {
  return `/api/config`;
};

export const updateConfig = async (
  appConfig: AppConfig,
  options?: RequestInit,
): Promise<MessageResponse> => {
  return customFetch<MessageResponse>(getUpdateConfigUrl(), {
    ...options,
    method: "PUT",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(appConfig),
  });
};

export const getUpdateConfigMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updateConfig>>,
    TError,
    { data: BodyType<AppConfig> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof updateConfig>>,
  TError,
  { data: BodyType<AppConfig> },
  TContext
> => {
  const mutationKey = ["updateConfig"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof updateConfig>>,
    { data: BodyType<AppConfig> }
  > = (props) => {
    const { data } = props ?? {};

    return updateConfig(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type UpdateConfigMutationResult = NonNullable<
  Awaited<ReturnType<typeof updateConfig>>
>;
export type UpdateConfigMutationBody = BodyType<AppConfig>;
export type UpdateConfigMutationError = ErrorType<unknown>;

